// 將 SB getEventList 結果對應到 Creator Service_Catalog 格式
const events = $json.result;
const mapped = [];

if (events && typeof events === 'object') {
  for (const [eventId, event] of Object.entries(events)) {
    mapped.push({
      Source: 'SimplyBook',
      External_ID: eventId,
      Name: event.name || '',
      Raw_Description: event.description || '',
      Price: parseFloat(event.price) || 0,
      Image_URL: event.picture_path ? `https://user-api.simplybook.me${event.picture_path}` : '',
      Active: event.is_active === '1' || event.is_active === true,
      Priority_Score: parseInt(event.position) || 0,
      Specifications: event.duration ? `時長：${event.duration} 分鐘` : ''
    });
  }
}

return [{ json: { service_list: mapped, count: mapped.length } }];
